def seed():
    sb = get_supabase()
    rows = []

    for h in HITTERS:
        prev_price = int((h["pj"] or 2) * WAR_DOLLAR)
        result = calc_price(
            player_type="H",
            projected_war=h["pj"],
            war_ytd=h["w"],
            games_played=GP,
            prev_price=prev_price,
            ownership_pct=0,
            season_ops=h.get("so"),
            recent_ops=h.get("r3"),
            hard_hit=h.get("hd"),
        )
        rows.append({
            "id": h["id"],
            "name": h["nm"],
            "team": h["tm"],
            "position": h["ps"],
            "player_type": "H",
            "eligible_positions": h["el"],
            "projected_war": h["pj"],
            "war_ytd": h["w"],
            "games_played": GP,
            "current_price": result["price"],
            "prev_price": prev_price,
            "season_ops": h.get("so"),
            "recent_ops": h.get("r3"),
            "hard_hit_pct": h.get("hd"),
        })

    for p in PITCHERS:
        prev_price = int((p["pj"] or 2) * WAR_DOLLAR)
        result = calc_price(
            player_type="P",
            projected_war=p["pj"],
            war_ytd=p["w"],
            games_played=GP,
            prev_price=prev_price,
            ownership_pct=0,
            season_era=p.get("se"),
            recent_era=p.get("r3"),
            hard_hit=p.get("hd"),
        )
        rows.append({
            "id": p["id"],
            "name": p["nm"],
            "team": p["tm"],
            "position": p["ps"],
            "player_type": "P",
            "eligible_positions": p["el"],
            "projected_war": p["pj"],
            "war_ytd": p["w"],
            "games_played": GP,
            "current_price": result["price"],
            "prev_price": prev_price,
            "season_era": p.get("se"),
            "recent_era": p.get("r3"),
            "hard_hit_pct": p.get("hd"),
        })

    # Upsert all players
    sb.table("players").upsert(rows, on_conflict="id").execute()
    print(f"Seeded {len(rows)} players ({len(HITTERS)} hitters, {len(PITCHERS)} pitchers)")


if __name__ == "__main__":
    seed()
